#!/usr/bin/env python3
"""AST transitive import closure for project-local modules, incl. lazy imports."""
import ast, os, sys
ROOT = "/home/polaris/wt/phase-file"

def mod_to_path(mod):
    p = os.path.join(ROOT, *mod.split("."))
    if os.path.isfile(p + ".py"):
        return p + ".py"
    if os.path.isdir(p) and os.path.isfile(os.path.join(p, "__init__.py")):
        return os.path.join(p, "__init__.py")
    return None

def imports_of(path, pkg):
    try:
        tree = ast.parse(open(path, encoding="utf-8").read())
    except SyntaxError as e:
        print(f"SYNTAX ERROR {path}: {e}", file=sys.stderr)
        return set()
    out = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for a in node.names:
                out.add(a.name)
        elif isinstance(node, ast.ImportFrom):
            if node.level:
                base = pkg.split(".")
                base = base[: len(base) - node.level + 1]
                m = ".".join(base + ([node.module] if node.module else []))
            else:
                m = node.module or ""
            out.add(m)
            for a in node.names:
                out.add(m + "." + a.name)
    return out

seeds = [
    "src.polaris_graph.generator.multi_section_generator",
    "src.polaris_graph.llm.openrouter_client",
    "src.polaris_graph.outline.outline_agent",
    "src.polaris_graph.authority.data_loader",
    "src.polaris_graph.planning.planning_gate_schema",
    "src.polaris_graph.planning.compose_render_projection",
    "src.polaris_graph.planning.contract_compliance",
]
seen, todo = set(), list(seeds)
while todo:
    m = todo.pop()
    if m in seen:
        continue
    p = mod_to_path(m)
    if not p:
        continue
    seen.add(m)
    pkg = m.rsplit(".", 1)[0] if p.endswith("__init__.py") is False else m
    for imp in imports_of(p, m if p.endswith("__init__.py") else m.rsplit(".", 1)[0]):
        # try full name and progressively stripped tails
        parts = imp.split(".")
        for i in range(len(parts), 0, -1):
            cand = ".".join(parts[:i])
            if mod_to_path(cand):
                if cand not in seen:
                    todo.append(cand)
                break

print(f"CLOSURE SIZE: {len(seen)}")
for m in sorted(seen):
    print(m)

